changeSet.sql:
-- Таймлайн конкретной сущности
CREATE INDEX IF NOT EXISTS idx_audit_entity
    ON ${schema}.audit_log (entity_type, entity_id, created_at DESC);

-- История действий пользователя
CREATE INDEX IF NOT EXISTS idx_audit_actor
    ON ${schema}.audit_log (actor_id, created_at DESC);

-- История статусов
CREATE INDEX IF NOT EXISTS idx_audit_status_changes
    ON ${schema}.audit_log (entity_type, entity_id, action)
    WHERE action = 'STATUS_CHANGED';

-- Поиск по JSON-данным (изменённые поля)
CREATE INDEX IF NOT EXISTS idx_audit_changes_gin
    ON ${schema}.audit_log USING GIN (changes);

rollback.sql:
DROP INDEX IF EXISTS ${schema}.idx_audit_entity;
DROP INDEX IF EXISTS ${schema}.idx_audit_actor;
DROP INDEX IF EXISTS ${schema}.idx_audit_status_changes;
DROP INDEX IF EXISTS ${schema}.idx_audit_changes_gin;

changeSet.sql:
COMMENT ON TABLE ${schema}.audit_log IS
    'Полная история изменений сущностей: заказы, задачи, клиенты, пользователи';
COMMENT ON COLUMN ${schema}.audit_log.entity_type IS
    'ORDER | TASK | CUSTOMER | USER | ROLE | MODULE';
COMMENT ON COLUMN ${schema}.audit_log.action IS
    'CREATED | UPDATED | STATUS_CHANGED | DELETED | COMMENT_ADDED | ASSIGNED';
COMMENT ON COLUMN ${schema}.audit_log.changes IS
    'JSON-diff: { "field": { "before": "...", "after": "..." } }';
